UPDATE program_days SET cards = '[{"type": "intro", "dayNumber": 1, "dayTitle": "Beginning the Journey", "phase": "Phase 1 \u00b7 Foundation", "phaseNumber": 1, "goal": "Complete Day 1 with steady, consistent action.", "estimatedMinutes": 25, "parameters": {"sets": 2, "reps": 3, "holdSeconds": 8, "durationMinutes": 25}}, {"type": "lesson", "pullQuote": null, "paragraphs": ["Isometric holds activate the superficial muscular aponeurotic system (SMAS) \u2014 the same muscle layer that a facelift targets. Consistent daily activation signals fibroblasts to produce more collagen."], "highlight": null}, {"type": "action_step", "stepLabel": "Step 1 \u00b7 Body Circulation", "title": "20-Minute Walk", "subtitle": "Wakes up circulation before facial exercises", "instructions": ["Walk at a comfortable pace for 20 minutes.", "Keep your posture upright, shoulders relaxed.", "Breathe naturally through the nose if possible."], "purpose": "Improves blood circulation, supports cellular energy production, and reduces physical tension before facial work."}, {"type": "exercise_routine", "category": "Isometric Hold", "name": "Cheek Lift Hold", "targetMuscle": "Zygomaticus muscles", "steps": ["Sit comfortably with your back straight.", "Smile as wide as possible.", "Place fingertips lightly on top of cheeks.", "Lift cheek muscles upward toward the eyes.", "Hold firmly."], "sets": 2, "reps": 3, "holdSeconds": 8, "scienceNote": "Trains the SMAS layer \u2014 the same muscle layer facelift surgery targets \u2014 through consistent isometric activation."}, {"type": "exercise_routine", "category": "Isometric Hold", "name": "Jawline Pucker Hold", "targetMuscle": "Masseter and neck muscles", "steps": ["Sit or stand with your back straight.", "Tilt your head slightly upward toward the ceiling.", "Pucker your lips as if kissing the ceiling.", "Feel the stretch under the jaw and neck.", "Hold firmly."], "sets": 2, "reps": 3, "holdSeconds": 8, "scienceNote": "Trains the SMAS layer \u2014 the same muscle layer facelift surgery targets \u2014 through consistent isometric activation."}, {"type": "mindfulness_exercise", "title": "Calm Session", "subtitle": "Nervous system reset", "steps": ["Open the app and tap the Calm button.", "Complete today''s guided calm session.", "If offline: sit quietly and take 20 slow breaths \u2014 inhale for 4 counts, exhale for 6 counts."], "benefits": ["Relaxes the nervous system", "Lowers cortisol \u2014 which directly slows skin aging", "Supports hormonal balance"], "timerSeconds": null, "completionMessage": "Stay with the practice until your body feels steadier."}, {"type": "action_step", "stepLabel": "Step 4 \u00b7 Sleep Preparation", "title": "Sleep Before 11 PM", "subtitle": "Growth hormone releases in deep sleep before midnight", "instructions": ["Aim to sleep before 11 PM tonight.", "Turn off screens 30 minutes before bed.", "Allow your body and mind to relax.", "Maintain a consistent sleep time."], "purpose": "Growth hormone \u2014 the body''s main skin repair hormone \u2014 is released primarily in deep sleep before midnight. Consistent sleep timing also supports female hormone balance."}, {"type": "close", "message": "Day 1 complete.", "secondaryMessage": "You showed up for beginning the journey today. Every day you return, the results compound."}]'::jsonb, estimated_minutes = 25 WHERE program_slug = 'age_reversal' AND day_number = 1;
